import React, { useEffect } from 'react';
import { Linking, Alert } from 'react-native';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';
import ProfileScreen from './ProfileScreen';
import PaymentConfirmScreen from './PaymentConfirmScreen';

const Stack = createStackNavigator();

const App = () => {
  useEffect(() => {
    const handleDeepLink = (event) => {
      const url = event.url;
      const { path, params } = parseUrl(url);

      if (path && params) {
        navigateToScreen(path, params);
      } else {
        Alert.alert('Invalid URL', 'The provided URL is not valid.');
      }
    };

    const parseUrl = (url) => {
      const supportedHosts = ['profile', 'payment'];
      const urlPattern = /^myapp:\/\/([^\/]+)\/([^\/]+)$/;
      const match = url.match(urlPattern);

      if (match && supportedHosts.includes(match[1])) {
        const path = match[1];
        const params = match[2];
        return { path, params };
      }
      return { path: null, params: null };
    };

    const navigateToScreen = (path, params) => {
      switch (path) {
        case 'profile':
          if (isValidProfileId(params)) {
            navigationRef.current?.navigate('Profile', { userId: params });
          } else {
            Alert.alert('Invalid Profile ID', 'The profile ID is not valid.');
          }
          break;
        case 'payment':
          if (params === 'confirm') {
            navigationRef.current?.navigate('PaymentConfirm');
          } else {
            Alert.alert('Invalid Payment Action', 'The payment action is not valid.');
          }
          break;
        default:
          Alert.alert('Invalid Path', 'The path is not recognized.');
      }
    };

    const isValidProfileId = (id) => {
      return /^[0-9]+$/.test(id);
    };

    Linking.addEventListener('url', handleDeepLink);

    return () => {
      Linking.removeEventListener('url', handleDeepLink);
    };
  }, []);

  return (
    <NavigationContainer ref={navigationRef}>
      <Stack.Navigator>
        <Stack.Screen name="Profile" component={ProfileScreen} />
        <Stack.Screen name="PaymentConfirm" component={PaymentConfirmScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
};

export default App;